// LÓGICA MAESTRA: Cruzar Usuario con Contenido (STRICT MATCHING)
// 1. Obtener inputs
const rawUsers = $("Traer Todos Usuarios").all()[0].json;
const allUsers = (rawUsers.records || []).map(r => r.fields);

const rawContent = $("Traer Todo Contenido").all()[0].json;
const allContent = (rawContent.records || []).map(r => r.fields);

const body = $("Webhook Portal").first().json.body;
const targetEmail = (body.email || "").toString().trim().toLowerCase();

// 2. Buscar Usuario
const user = allUsers.find(u => {
  const emailDB = (u.EMAIL || "").toString().trim().toLowerCase();
  return emailDB === targetEmail;
});

if (!user) {
  return [{ json: { error: "Usuario no encontrado" } }];
}

// Validar que el usuario tenga ESTADO = 'Activo'
const userEstado = (user.ESTADO || "").toString().trim().toLowerCase();
if (userEstado !== "activo") {
  return [{ json: { error: "Usuario no autorizado. Estado: " + user.ESTADO } }];
}

function cleanString(val) {
    if (!val) return "";
    if (Array.isArray(val)) return val[0].toString().trim().toLowerCase();
    return val.toString().trim().toLowerCase();
}

const userRole = cleanString(user['ROL OPERATIVO']);

const matchingContent = allContent.filter(c => {
    const rawRole = c['ROL'];
    let contentRoles = [];
    if (Array.isArray(rawRole)) {
        contentRoles = rawRole.map(r => r.toString().trim().toLowerCase());
    } else if (rawRole) {
        contentRoles = [rawRole.toString().trim().toLowerCase()];
    }
    return contentRoles.includes(userRole);
});

let content;
if (matchingContent.length > 0) {
   const randomIndex = Math.floor(Math.random() * matchingContent.length);
   content = matchingContent[randomIndex];
} else {
   content = null;
}

let imageUrl = "";
let defaultImage = "https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80";

if (content && content["FOTOS DEL PORTAL"] && content["FOTOS DEL PORTAL"].length > 0) {
  imageUrl = content["FOTOS DEL PORTAL"][0].url;
} else {
  imageUrl = defaultImage;
}

function safeText(val) {
    if (!val) return "Bienvenido a tu espacio de trabajo.";
    if (typeof val === 'string') return val;
    if (Array.isArray(val)) return safeText(val[0]);
    if (typeof val === 'object') {
        const values = Object.values(val);
        const candidates = values.filter(v => typeof v === 'string' && v.length > 10);
        if (candidates.length > 0) return candidates.reduce((a, b) => a.length > b.length ? a : b);
        return values.filter(v => v !== 'generated' && v !== false && v !== true && v !== null).join(" ");
    }
    return String(val);
}

let rawQuote = content ? content["FRASES DEL PORTAL"] : null;
let finalQuote = safeText(rawQuote);

return [{
  json: {
    role: user['ROL OPERATIVO'],
    name: user['NOMBRE'] || user.EMAIL.split('@')[0],
    email: targetEmail,
    status: user.ESTADO,
    originalUrl: user.URL_PORTAL,
    theme: {
      quote: finalQuote,
      imageUrl: imageUrl
    }
  }
}];

// Generar Token Único y calcular expiración
const data = $input.first().json;

// Generar UUID v4
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const token = uuidv4() + '-' + Date.now().toString(36);

// Expiración: 10 minutos desde ahora
const expiraDate = new Date(Date.now() + 10 * 60 * 1000);
const expiraISO = expiraDate.toISOString();

// URL enmascarada
const maskedUrl = 'https://primary-production-0abcf.up.railway.app/webhook/redirect?token=' + token;

return [{
  json: {
    ...data,
    token: token,
    expira: expiraISO,
    maskedUrl: maskedUrl
  }
}];

// Preparar respuesta final con URL enmascarada
const prevData = $('Generar Token').first().json;

return [{
  json: {
    role: prevData.role,
    name: prevData.name,
    status: prevData.status,
    destinationUrl: prevData.maskedUrl,
    theme: prevData.theme
  }
}];
